const payload = $json || {};
const userQuery = String(payload.user_query || payload.prompt || '').trim();
if (!userQuery) {
  throw new Error('Missing user_query/prompt in webhook payload.');
}
const summaryMode = String(payload.summary_mode || 'analyst').trim().toLowerCase() || 'analyst';
const dashboardFilters = payload.dashboard_filters && typeof payload.dashboard_filters === 'object' ? payload.dashboard_filters : {};

return [{
  json: {
    user_query: userQuery,
    summary_mode: summaryMode,
    dashboard_filters: dashboardFilters
  }
}];

const contextResponse = $json || {};
if (!contextResponse.ok) {
  const err = String(contextResponse.error || 'ThreatFoundry context API call failed.');
  throw new Error(err);
}

const userQuery = String(contextResponse.user_query || '').trim();
const summaryMode = String(contextResponse.summary_mode || 'analyst').trim().toLowerCase();
const iocContext = contextResponse.ioc_context && typeof contextResponse.ioc_context === 'object' ? contextResponse.ioc_context : {};
const metrics = iocContext.metrics && typeof iocContext.metrics === 'object' ? iocContext.metrics : {};
const lookup = iocContext.lookup && typeof iocContext.lookup === 'object' ? iocContext.lookup : {};

const totalIocs = Number(metrics.total_iocs || 0);
const hasSpecificTargets = !!lookup.has_specific_targets;
const foundAnyTargets = !!lookup.found_any;
const hasRelevantData = totalIocs > 0 && (!hasSpecificTargets || foundAnyTargets);

const groundingRules = [
  'Use ONLY the provided ThreatFoundry IOC context as source of truth.',
  'Do not invent indicators, sources, confidence values, or timelines.',
  'If the provided context does not support the answer, state that clearly.',
  'When possible, cite concrete metrics, IOC values, and source names from context.'
];

const modelPrompt = [
  'SYSTEM INSTRUCTIONS:',
  ...groundingRules.map((line) => `- ${line}`),
  '',
  `Requested summary mode: ${summaryMode || 'analyst'}`,
  `Analyst question: ${userQuery}`,
  '',
  'ThreatFoundry context JSON:',
  JSON.stringify(iocContext, null, 2),
  '',
  'Return a direct analyst answer followed by concise bullet findings and actions.'
].join('\n');

return [{
  json: {
    user_query: userQuery,
    summary_mode: summaryMode || 'analyst',
    has_relevant_data: hasRelevantData,
    no_data_reason: !hasRelevantData
      ? (totalIocs === 0
          ? 'No IOC records are available in the current ThreatFoundry scope.'
          : 'No records matched the specific IOC target(s) in this scope.')
      : '',
    ioc_context: iocContext,
    model_prompt: modelPrompt
  }
}];

const upstream = ($items('Build Grounded Prompt', 0, 0)[0] || {}).json || {};
const iocContext = upstream.ioc_context && typeof upstream.ioc_context === 'object' ? upstream.ioc_context : {};
const lookup = iocContext.lookup && typeof iocContext.lookup === 'object' ? iocContext.lookup : {};

const modelResponse = String(($json || {}).response || '').trim();
const answer = modelResponse || 'Model did not return text. ThreatFoundry data could not be summarized safely.';

const supportingRecords = lookup.found_any && Array.isArray(lookup.results) && lookup.results.length
  ? (((lookup.results.find((row) => Number(row.matched_count || 0) > 0) || {}).top_records) || []).slice(0, 5)
  : (Array.isArray(iocContext.top_suspicious) ? iocContext.top_suspicious.slice(0, 5) : []);

return [{
  json: {
    answer,
    key_findings: [
      `Scoped IOC count: ${Number((iocContext.metrics || {}).total_iocs || 0)}.`,
      `High-confidence IOC count: ${Number((iocContext.metrics || {}).high_confidence_iocs || 0)}.`
    ],
    recommended_actions: [
      'Validate the top supporting IOCs in the ThreatFoundry IOC detail view.',
      'Prioritize high-confidence indicators for immediate triage.',
      'Pivot on source and malware family for campaign-level linkage.'
    ],
    uncertainty: [],
    supporting_records: supportingRecords,
    provider: 'n8n-ollama',
    source_of_truth: 'threatfoundry_database'
  }
}];

const payload = $json || {};
return [{
  json: {
    answer: String(payload.no_data_reason || 'No relevant ThreatFoundry data was found for this question.'),
    key_findings: [
      'The workflow intentionally avoided generating unsupported conclusions.'
    ],
    recommended_actions: [
      'Adjust dashboard filters or IOC target format and retry the query.',
      'Ingest additional IOC data if the scope is currently empty.'
    ],
    uncertainty: [
      'No relevant IOC evidence was available in the scoped ThreatFoundry dataset.'
    ],
    supporting_records: [],
    provider: 'n8n-ollama',
    source_of_truth: 'threatfoundry_database'
  }
}];
